#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X, Y;
        scanf("%d %d", &X, &Y);
        int ans = X > Y ? X - Y : 0;
        printf("%d\n", ans);
    }
    return 0;
}

